 49→/** Build common headers, optionally including the API key. */
 50→function buildHeaders(): Record<string, string> {
 51→  const headers: Record<string, string> = {
 52→    Accept: "application/json",
 53→  };
 54→  if (config.SEMANTIC_SCHOLAR_API_KEY) {
 55→    headers["x-api-key"] = config.SEMANTIC_SCHOLAR_API_KEY;
 56→  }
 57→  return headers;
 58→}
