 60→/** Thin wrapper around fetch that handles common error scenarios. */
 61→async function s2Fetch<T>(url: string): Promise<T> {
 62→  let response: Response;
 63→  try {
 64→    response = await fetch(url, { headers: buildHeaders() });
 65→  } catch (err: unknown) {
 66→    const message =
 67→      err instanceof Error ? err.message : "Unknown network error";
 68→    throw new Error(`Semantic Scholar API network error: ${message}`);
 69→  }
 70→
 71→  if (response.status === 429) {
 72→    throw new Error(
 73→      "Semantic Scholar API rate limit exceeded (HTTP 429). " +
 74→        "Please wait before retrying, or set SEMANTIC_SCHOLAR_API_KEY for higher limits."
 75→    );
 76→  }
 77→
 78→  if (!response.ok) {
 79→    const body = await response.text().catch(() => "");
 80→    throw new Error(
 81→      `Semantic Scholar API error: ${response.status} ${response.statusText}` +
 82→        (body ? ` — ${body}` : "")
 83→    );
 84→  }
 85→
 86→  return response.json() as Promise<T>;
 87→}
