  1→import config from "./env";
  2→
  3→// ---------------------------------------------------------------------------
  4→// Types
  5→// ---------------------------------------------------------------------------
  6→
  7→/** A single autocomplete match returned by Semantic Scholar. */
  8→export interface PaperMatch {
  9→  id: string;
 10→  title: string;
 11→  authorsYear: string;
 12→}
 13→
 14→/** Shape of the autocomplete API response. */
 15→interface AutocompleteResponse {
 16→  matches: PaperMatch[];
 17→}
 18→
 19→/** Author object returned by the paper detail endpoint. */
 20→export interface Author {
 21→  authorId: string;
 22→  name: string;
 23→}
 24→
 25→/** Embedding payload included when requesting the `embedding` field. */
 26→export interface PaperEmbedding {
 27→  model: string;
 28→  vector: number[];
 29→}
 30→
 31→/** Full paper object returned by getPaper. */
 32→export interface Paper {
 33→  paperId: string;
 34→  title: string;
 35→  url: string;
 36→  year: number | null;
 37→  authors: Author[];
 38→  abstract: string | null;
 39→  embedding: {
 40→    specter_v2: PaperEmbedding | null;
 41→  } | null;
 42→}
 43→
 44→// ---------------------------------------------------------------------------
 45→// Helpers
 46→// ---------------------------------------------------------------------------
 47→
 48→const S2_BASE = "https://api.semanticscholar.org/graph/v1";
 49→
 50→/** Build common headers, optionally including the API key. */
 51→function buildHeaders(): Record<string, string> {
 52→  const headers: Record<string, string> = {
 53→    Accept: "application/json",
 54→  };
 55→  if (config.SEMANTIC_SCHOLAR_API_KEY) {
 56→    headers["x-api-key"] = config.SEMANTIC_SCHOLAR_API_KEY;
 57→  }
 58→  return headers;
 59→}
 60→
 61→/** Thin wrapper around fetch that handles common error scenarios. */
 62→async function s2Fetch<T>(url: string): Promise<T> {
 63→  let response: Response;
 64→  try {
 65→    response = await fetch(url, { headers: buildHeaders() });
 66→  } catch (err: unknown) {
 67→    const message =
 68→      err instanceof Error ? err.message : "Unknown network error";
 69→    throw new Error(`Semantic Scholar API network error: ${message}`);
 70→  }
 71→
 72→  if (response.status === 429) {
 73→    throw new Error(
 74→      "Semantic Scholar API rate limit exceeded (HTTP 429). " +
 75→        "Please wait before retrying, or set SEMANTIC_SCHOLAR_API_KEY for higher limits."
 76→    );
 77→  }
 78→
 79→  if (!response.ok) {
 80→    const body = await response.text().catch(() => "");
 81→    throw new Error(
 82→      `Semantic Scholar API error: ${response.status} ${response.statusText}` +
 83→        (body ? ` — ${body}` : "")
 84→    );
 85→  }
 86→
 87→  return response.json() as Promise<T>;
 88→}
 89→
 90→// ---------------------------------------------------------------------------
 91→// Public API
 92→// ---------------------------------------------------------------------------
 93→
 94→/**
 95→ * Search for papers using the Semantic Scholar autocomplete endpoint.
 96→ *
 97→ * @param query - Free-text search query.
 98→ * @returns Array of matching papers with `id`, `title`, and `authorsYear`.
 99→ */
100→export async function searchPapers(query: string): Promise<PaperMatch[]> {
101→  const url = `${S2_BASE}/paper/autocomplete?query=${encodeURIComponent(query)}`;
102→  const data = await s2Fetch<AutocompleteResponse>(url);
103→  return data.matches;
104→}
105→
106→/**
107→ * Fetch full details for a single paper by its Semantic Scholar paper ID.
108→ *
109→ * Requests: url, year, authors, abstract, embedding (including specter_v2).
110→ *
111→ * @param paperId - Semantic Scholar paper ID.
112→ * @returns Full paper object.
113→ */
114→export async function getPaper(paperId: string): Promise<Paper> {
115→  const fields = "url,year,authors,abstract,embedding";
116→  const url = `${S2_BASE}/paper/${encodeURIComponent(paperId)}?fields=${fields}`;
117→  return s2Fetch<Paper>(url);
118→}
