 1→import { LambdaClient, InvokeCommand } from "@aws-sdk/client-lambda";
 2→import config from "./env";
 3→
 4→// ---------------------------------------------------------------------------
 5→// Lambda client
 6→// ---------------------------------------------------------------------------
 7→
 8→const lambdaClient = new LambdaClient({ region: config.AWS_REGION });
 9→
10→// ---------------------------------------------------------------------------
11→// Types
12→// ---------------------------------------------------------------------------
13→
14→interface LambdaResponseBody {
15→  embedding: number[];
16→  model: string;
17→  dimensions: number;
18→}
19→
20→interface LambdaPayload {
21→  statusCode: number;
22→  body: string;
23→}
24→
25→// ---------------------------------------------------------------------------
26→// Public API
27→// ---------------------------------------------------------------------------
28→
29→/**
30→ * Invoke the AWS Lambda embedding function to generate an OpenAI embedding
31→ * for the given text.
32→ *
33→ * @param text - The text to embed.
34→ * @returns The embedding vector (number[]).
35→ * @throws If the Lambda invocation fails or returns an error.
36→ */
37→export async function generateEmbedding(text: string): Promise<number[]> {
38→  const command = new InvokeCommand({
39→    FunctionName: config.AWS_LAMBDA_FUNCTION_NAME,
40→    Payload: new TextEncoder().encode(JSON.stringify({ text })),
41→  });
42→
43→  const response = await lambdaClient.send(command);
44→
45→  if (response.FunctionError) {
46→    throw new Error(
47→      `Lambda function error: ${response.FunctionError} — ${
48→        response.Payload
49→          ? new TextDecoder().decode(response.Payload)
50→          : "no payload"
51→      }`
52→    );
53→  }
54→
55→  if (!response.Payload) {
56→    throw new Error("Lambda returned no payload");
57→  }
58→
59→  const raw = new TextDecoder().decode(response.Payload);
60→  const lambdaResult: LambdaPayload = JSON.parse(raw);
61→
62→  if (lambdaResult.statusCode !== 200) {
63→    throw new Error(
64→      `Lambda returned status ${lambdaResult.statusCode}: ${lambdaResult.body}`
65→    );
66→  }
67→
68→  const body: LambdaResponseBody = JSON.parse(lambdaResult.body);
69→
70→  if (!Array.isArray(body.embedding) || body.embedding.length === 0) {
71→    throw new Error("Lambda returned an invalid or empty embedding");
72→  }
73→
74→  return body.embedding;
75→}
