 1→import { NextRequest, NextResponse } from "next/server";
 2→import { initCollection, paperExists, insertPaper } from "@/lib/zilliz";
 3→import { getPaper } from "@/lib/semantic-scholar";
 4→import { generateEmbedding } from "@/lib/lambda";
 5→
 6→/**
 7→ * POST /api/papers/[paperId]/vectorize
 8→ *
 9→ * Vectorizes a paper by:
10→ * 1. Checking the guard (paper must not already be vectorized)
11→ * 2. Fetching paper data from Semantic Scholar
12→ * 3. Generating an OpenAI embedding for the abstract via Lambda
13→ * 4. Extracting the SPECTER v2 embedding from the S2 response
14→ * 5. Storing the paper + both embeddings in Zilliz
15→ */
16→export async function POST(
17→  _request: NextRequest,
18→  { params }: { params: Promise<{ paperId: string }> }
19→) {
20→  const { paperId } = await params;
21→
22→  try {
23→    // Ensure collection exists
24→    await initCollection();
25→
26→    // Guard: check if paper is already vectorized
27→    const exists = await paperExists(paperId);
28→    if (exists) {
29→      return NextResponse.json(
30→        { canVectorize: false, reason: "Paper already vectorized" },
31→        { status: 409 }
32→      );
33→    }
34→
35→    // Fetch paper details from Semantic Scholar
36→    const paper = await getPaper(paperId);
37→
38→    // Validate that the paper has an abstract (required for embedding)
39→    if (!paper.abstract) {
40→      return NextResponse.json(
41→        {
42→          error:
43→            "Paper has no abstract and cannot be vectorized. An abstract is required to generate an embedding.",
44→        },
45→        { status: 400 }
46→      );
47→    }
48→
49→    // Generate OpenAI embedding for the abstract via Lambda
50→    const openaiEmbedding = await generateEmbedding(paper.abstract);
51→
52→    // Extract SPECTER v2 embedding from the Semantic Scholar response
53→    const specterVector = paper.embedding?.specter_v2?.vector;
54→    if (!specterVector || specterVector.length === 0) {
55→      return NextResponse.json(
56→        {
57→          error:
58→            "Paper does not have a SPECTER v2 embedding from Semantic Scholar.",
59→        },
60→        { status: 400 }
61→      );
62→    }
63→
64→    // Build the paper record
65→    const vectorizedAt = Date.now();
66→    const authorsString = paper.authors.map((a) => a.name).join(", ");
67→
68→    await insertPaper({
69→      paperId: paper.paperId,
70→      title: paper.title,
71→      authors: authorsString,
72→      year: paper.year ?? 0,
73→      abstract: paper.abstract,
74→      url: paper.url,
75→      vectorizedAt,
76→      openai_embedding: openaiEmbedding,
77→      specter_v2_embedding: specterVector,
78→    });
79→
80→    // Return success with paper metadata
81→    return NextResponse.json({
82→      paperId: paper.paperId,
83→      title: paper.title,
84→      authors: paper.authors,
85→      year: paper.year,
86→      abstract: paper.abstract,
87→      url: paper.url,
88→      vectorized: true,
89→      vectorizedAt,
90→    });
91→  } catch (err: unknown) {
92→    const message =
93→      err instanceof Error ? err.message : "Internal server error";
94→    console.error(`[vectorize] Error vectorizing paper ${paperId}:`, err);
95→    return NextResponse.json({ error: message }, { status: 500 });
96→  }
97→}
