 1→import { NextRequest, NextResponse } from "next/server";
 2→import { searchPapers } from "@/lib/semantic-scholar";
 3→import { initCollection, paperExists } from "@/lib/zilliz";
 4→
 5→/**
 6→ * GET /api/papers/search?q={query}
 7→ *
 8→ * Searches Semantic Scholar for papers matching the query, then checks
 9→ * Zilliz to determine if each paper has already been vectorized.
10→ *
11→ * Returns a JSON array of { id, title, authorsYear, vectorized }.
12→ */
13→export async function GET(request: NextRequest) {
14→  const q = request.nextUrl.searchParams.get("q");
15→
16→  if (!q || q.trim() === "") {
17→    return NextResponse.json(
18→      { error: "Missing or empty query parameter 'q'" },
19→      { status: 400 }
20→    );
21→  }
22→
23→  // Ensure the Zilliz collection exists before querying it.
24→  await initCollection();
25→
26→  const papers = await searchPapers(q);
27→
28→  const results = await Promise.all(
29→    papers.map(async (paper) => {
30→      const vectorized = await paperExists(paper.id);
31→      return {
32→        id: paper.id,
33→        title: paper.title,
34→        authorsYear: paper.authorsYear,
35→        vectorized,
36→      };
37→    })
38→  );
39→
40→  return NextResponse.json(results);
41→}
