import { useState, useEffect, useRef, useCallback } from "react";

// ── Types ──────────────────────────────────────────────────────────────────

interface PaperResult {
  id: string;
  title: string;
  authorsYear: string;
  vectorized: boolean;
}

interface Toast {
  id: number;
  message: string;
  type: "success" | "error";
}

// ── Toast Container ────────────────────────────────────────────────────────

function ToastContainer({
  toasts,
  onDismiss,
}: {
