346→                        <span className="inline-flex items-center rounded-full bg-gray-50 px-2.5 py-0.5 text-xs font-medium text-gray-600 ring-1 ring-gray-500/10 ring-inset">
347→                          Not vectorized
348→                        </span>
349→                      )}
350→
351→                      {/* Vectorize button */}
352→                      <button
353→                        onClick={() => handleVectorize(paper.id)}
354→                        disabled={paper.vectorized || isVectorizing}
355→                        className={`inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium transition-colors ${
356→                          paper.vectorized
357→                            ? "cursor-not-allowed bg-gray-100 text-gray-400"
358→                            : isVectorizing
359→                              ? "cursor-wait bg-blue-600 text-white"
360→                              : "bg-blue-600 text-white hover:bg-blue-700 active:bg-blue-800"
361→                        }`}
362→                      >
363→                        {isVectorizing && <Spinner />}
364→                        {isVectorizing ? "Vectorizing..." : "Vectorize"}
365→                      </button>
366→                    </div>
367→                  </li>
368→                );
369→              })}
370→            </ul>
371→          </div>
372→        )}
373→
374→        {/* Empty state when search returns no results */}
375→        {showDropdown && results.length === 0 && !isSearching && query.trim() && (
376→          <div className="absolute z-40 mt-2 w-full rounded-xl border border-gray-200 bg-white p-6 text-center shadow-lg">
377→            <p className="text-sm text-gray-500">
378→              No papers found for &ldquo;{query}&rdquo;
379→            </p>
380→          </div>
381→        )}
382→      </div>
383→    </main>
384→  );
385→}
